import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import sun.misc.Unsafe;

class ValueStoreHashCacheTest {

	private static final Unsafe UNSAFE = initUnsafe();

	private ValueStore valueStore;

	@Test
	void defaultConfigShouldNotPersistHashCache(@TempDir File dataDir) throws Exception {
		valueStore = createValueStore(dataDir, new LmdbStoreConfig());

		IRI iri = Values.iri("urn:hash:default-disabled");
		int expectedHash = iri.hashCode();
		long id = storeValue(iri);

		assertFalse(hashFile(dataDir).exists());

		valueStore.close();
		valueStore = createValueStore(dataDir, new LmdbStoreConfig());

		LmdbIRI lazyValue = (LmdbIRI) valueStore.getLazyValue(id);
		assertFalse(isInitialized(lazyValue));
		assertEquals(expectedHash, lazyValue.hashCode());
		assertTrue("hashCode should initialize lazy IRIs when the hash cache is disabled", isInitialized(lazyValue));
		assertFalse(hashFile(dataDir).exists());
		assertFalse(integrityFile(dataDir).exists());
	}

	@Test
	void enabledHashCacheShouldWriteIntegrityFileAndClearItOnOpen(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = hashCacheEnabledConfig();
		valueStore = createValueStore(dataDir, config);

		IRI iri = Values.iri("urn:hash:integrity-clean");
		int expectedHash = iri.hashCode();
		long id = storeValue(iri);

		valueStore.close();
		valueStore = null;

		assertTrue(hashFile(dataDir).exists());
		assertTrue("clean shutdown should create hash cache integrity metadata", integrityFile(dataDir).exists());

		valueStore = createValueStore(dataDir, config);

		assertFalse("startup should remove integrity metadata until the next clean shutdown",
				integrityFile(dataDir).exists());

		LmdbIRI lazyValue = (LmdbIRI) valueStore.getLazyValue(id);
		assertFalse(isInitialized(lazyValue));
		assertEquals(expectedHash, lazyValue.hashCode());
		assertFalse("validated cache should keep lazy IRIs unresolved", isInitialized(lazyValue));
	}

	@Test
	void enabledHashCacheShouldDropCacheWhenIntegrityFileIsMissing(@TempDir File dataDir) throws Exception {
		assertCorruptedCacheFallsBackToRecomputedHash(dataDir, file -> assertTrue(file.delete()), false);
	}

	@Test
	void enabledHashCacheShouldDropCacheWhenHashFileIsCorrupted(@TempDir File dataDir) throws Exception {
		assertCorruptedCacheFallsBackToRecomputedHash(dataDir, file -> {
			try (RandomAccessFile randomAccessFile = new RandomAccessFile(file, "rw")) {
				randomAccessFile.seek(0);
				randomAccessFile.writeInt(0x10203040);
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}, true);
	}

	@Test
	void enabledHashCacheShouldDropCacheWhenIntegrityMetadataIsCorrupted(@TempDir File dataDir) throws Exception {
		assertCorruptedCacheFallsBackToRecomputedHash(dataDir, file -> {
			try {
				Files.writeString(file.toPath(), "broken");
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}, false);
	}

	@Test
	void deleteShouldCleanMappedSegments(@TempDir File dataDir) throws Exception {
		File valuesDir = new File(dataDir, "values");
		assertTrue(valuesDir.mkdirs());

		ValueStoreHashFile hashFile = new ValueStoreHashFile(valuesDir);
		hashFile.put(1L, 1234);

		MappedByteBuffer segment = firstSegment(hashFile);
		Object cleaner = cleaner(segment);
		Field nodeField = cleaner.getClass().getDeclaredField("node");
		assertNotNull("mapped segment should still be registered before delete", readObject(cleaner, nodeField));

		hashFile.delete();

		assertNull("delete should explicitly clean mapped segments before removing the file",
				readObject(cleaner, nodeField));
	}

	private void assertCorruptedCacheFallsBackToRecomputedHash(File dataDir, Consumer<File> corruptor,
			boolean corruptHashFile) throws Exception {
		LmdbStoreConfig config = hashCacheEnabledConfig();
		valueStore = createValueStore(dataDir, config);

		IRI iri = Values.iri("urn:hash:corrupt");
		int expectedHash = iri.hashCode();
		long id = storeValue(iri);

		valueStore.close();
		valueStore = null;

		corruptor.accept(corruptHashFile ? hashFile(dataDir) : integrityFile(dataDir));

		valueStore = createValueStore(dataDir, config);

		LmdbIRI lazyValue = (LmdbIRI) valueStore.getLazyValue(id);
		assertFalse(isInitialized(lazyValue));
		assertEquals(expectedHash, lazyValue.hashCode());
		assertTrue("invalid cache metadata should force lazy IRIs to recompute their hash", isInitialized(lazyValue));
	}

	private ValueStore createValueStore(File dataDir, LmdbStoreConfig config) throws IOException {
		return new ValueStore(new File(dataDir, "values"), config);
	}

	private long storeValue(IRI iri) throws Exception {
		valueStore.startTransaction(true);
		long id = valueStore.storeValue(iri);
		valueStore.commit();
		return id;
	}

	private LmdbStoreConfig hashCacheEnabledConfig() {
		return new LmdbStoreConfig().setValueHashCacheEnabled(true);
	}

	private File hashFile(File dataDir) {
		return new File(new File(dataDir, "values"), ValueStoreHashFile.FILE_NAME);
	}

	private File integrityFile(File dataDir) {
		return new File(new File(dataDir, "values"), ValueStoreHashFile.INTEGRITY_FILE_NAME);
	}

	private boolean isInitialized(Object value) throws Exception {
		Field initializedField = value.getClass().getDeclaredField("initialized");
		initializedField.setAccessible(true);
		return initializedField.getBoolean(value);
	}

	@SuppressWarnings("unchecked")
	private MappedByteBuffer firstSegment(ValueStoreHashFile hashFile) throws Exception {
		Field segmentsField = ValueStoreHashFile.class.getDeclaredField("segments");
		segmentsField.setAccessible(true);
		List<MappedByteBuffer> segments = (List<MappedByteBuffer>) segmentsField.get(hashFile);
		return segments.get(0);
	}

	private Object cleaner(MappedByteBuffer segment) throws Exception {
		Field cleanerField = segment.getClass().getDeclaredField("cleaner");
		return readObject(segment, cleanerField);
	}

	private Object readObject(Object target, Field field) {
		return UNSAFE.getObject(target, UNSAFE.objectFieldOffset(field));
	}

	private static Unsafe initUnsafe() {
		try {
			Field theUnsafe = Unsafe.class.getDeclaredField("theUnsafe");
			theUnsafe.setAccessible(true);
			return (Unsafe) theUnsafe.get(null);
		} catch (ReflectiveOperationException e) {
			throw new ExceptionInInitializerError(e);
		}
	}

	@AfterEach
	void after() throws Exception {
		if (valueStore != null) {
			valueStore.close();
		}
	}
}
